import{_ as a,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Obsidian 集成: 自动保存计划 | plannotator","description":"学习 plannotator 的 Obsidian 集成配置方法。自动保存批准的计划到 vault，包含 frontmatter 和标签生成功能，支持自定义保存路径。","frontmatter":{"title":"Obsidian 集成: 自动保存计划 | plannotator","sidebarTitle":"自动保存到 Obsidian","subtitle":"Obsidian 集成: 自动保存计划 | plannotator","description":"学习 plannotator 的 Obsidian 集成配置方法。自动保存批准的计划到 vault，包含 frontmatter 和标签生成功能，支持自定义保存路径。","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh/backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"zh/backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),n={name:"zh/backnotprop/plannotator/advanced/obsidian-integration/index.md"};function r(l,t,s,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="obsidian-集成-自动保存计划到笔记库" tabindex="-1">Obsidian 集成：自动保存计划到笔记库 <a class="header-anchor" href="#obsidian-集成-自动保存计划到笔记库" aria-label="Permalink to &quot;Obsidian 集成：自动保存计划到笔记库&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>自动将批准或拒绝的计划保存到 Obsidian vault</li><li>理解 frontmatter 和标签的生成机制</li><li>自定义保存路径和文件夹</li><li>利用 backlink 构建知识图谱</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你在 Plannotator 中评审 AI 生成的计划，批准后这些计划就&quot;消失&quot;了。你希望把这些有价值的计划保存到 Obsidian，方便后续回顾和查找，但手动复制粘贴太麻烦，而且格式会乱。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你使用 Obsidian 作为知识管理工具</li><li>你希望长期保存和回顾 AI 生成的实施计划</li><li>你想利用 Obsidian 的 graph view 和标签系统组织计划</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Plannotator 的 Obsidian 集成功能会在你批准或拒绝计划时，自动将计划内容保存到你的 Obsidian vault。系统会：</p><ol><li><strong>检测 vaults</strong>：自动从 Obsidian 配置文件读取所有 vault</li><li><strong>生成 frontmatter</strong>：包含创建时间、来源和标签</li><li><strong>提取标签</strong>：从计划标题和代码块语言自动提取标签</li><li><strong>添加 backlink</strong>：插入 <code>[[Plannotator Plans]]</code> 链接，方便构建知识图谱</li></ol><div class="info custom-block"><p class="custom-block-title">什么是 Obsidian？</p><p>Obsidian 是一款本地优先的双向链接笔记应用，支持 Markdown 格式，可通过图视图可视化笔记之间的关系。</p></div><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p>确保已安装并配置好 Obsidian。Plannotator 会自动检测系统中的 vaults，但你至少需要有一个 vault 才能使用此功能。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-打开设置面板" tabindex="-1">第 1 步：打开设置面板 <a class="header-anchor" href="#第-1-步-打开设置面板" aria-label="Permalink to &quot;第 1 步：打开设置面板&quot;">​</a></h3><p>在 Plannotator 界面中，点击右上角的齿轮图标打开设置面板。</p><p>你应该看到设置对话框，包含多个配置选项。</p><h3 id="第-2-步-启用-obsidian-集成" tabindex="-1">第 2 步：启用 Obsidian 集成 <a class="header-anchor" href="#第-2-步-启用-obsidian-集成" aria-label="Permalink to &quot;第 2 步：启用 Obsidian 集成&quot;">​</a></h3><p>在设置面板中找到&quot;Obsidian Integration&quot;部分，点击开关启用该功能。</p><p>启用后，Plannotator 会自动检测系统中的 Obsidian vaults。</p><p>你应该看到下拉菜单中列出检测到的 vaults（例如 <code>My Vault</code>、<code>Work Notes</code>）。</p><h3 id="第-3-步-选择-vault-和文件夹" tabindex="-1">第 3 步：选择 vault 和文件夹 <a class="header-anchor" href="#第-3-步-选择-vault-和文件夹" aria-label="Permalink to &quot;第 3 步：选择 vault 和文件夹&quot;">​</a></h3><p>从下拉菜单中选择你希望保存计划的 vault。如果没有检测到 vault，可以：</p><ol><li>选择&quot;Custom path...&quot;选项</li><li>在文本框中输入 vault 的完整路径</li></ol><p>然后在&quot;Folder&quot;字段中设置保存文件夹的名称（默认为 <code>plannotator</code>）。</p><p>你应该看到下方的预览路径，显示计划将保存的位置。</p><h3 id="第-4-步-批准或拒绝计划" tabindex="-1">第 4 步：批准或拒绝计划 <a class="header-anchor" href="#第-4-步-批准或拒绝计划" aria-label="Permalink to &quot;第 4 步：批准或拒绝计划&quot;">​</a></h3><p>配置完成后，正常评审 AI 生成的计划。当你点击&quot;Approve&quot;或&quot;Send Feedback&quot;时，计划会自动保存到配置的 vault 中。</p><p>你应该在 Obsidian 中看到新创建的文件，文件名格式为 <code>Title - Jan 2, 2026 2-30pm.md</code>。</p><h3 id="第-5-步-查看保存的文件" tabindex="-1">第 5 步：查看保存的文件 <a class="header-anchor" href="#第-5-步-查看保存的文件" aria-label="Permalink to &quot;第 5 步：查看保存的文件&quot;">​</a></h3><p>在 Obsidian 中打开保存的文件，你会看到以下内容：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>你应该注意到文件顶部有 YAML frontmatter，包含创建时间、来源和标签。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 设置面板中 Obsidian Integration 已启用</li><li>[ ] 已选择 vault（或输入了自定义路径）</li><li>[ ] 已设置文件夹名称</li><li>[ ] 批准或拒绝计划后，Obsidian 中出现新文件</li><li>[ ] 文件包含 frontmatter 和 <code>[[Plannotator Plans]]</code> backlink</li></ul><h2 id="frontmatter-和标签详解" tabindex="-1">Frontmatter 和标签详解 <a class="header-anchor" href="#frontmatter-和标签详解" aria-label="Permalink to &quot;Frontmatter 和标签详解&quot;">​</a></h2><h3 id="frontmatter-结构" tabindex="-1">Frontmatter 结构 <a class="header-anchor" href="#frontmatter-结构" aria-label="Permalink to &quot;Frontmatter 结构&quot;">​</a></h3><p>每个保存的计划都包含以下 frontmatter 字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>值示例</th><th>说明</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>ISO 8601 格式的创建时间戳</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>固定值，标识来源</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>自动提取的标签数组</td></tr></tbody></table><h3 id="标签生成规则" tabindex="-1">标签生成规则 <a class="header-anchor" href="#标签生成规则" aria-label="Permalink to &quot;标签生成规则&quot;">​</a></h3><p>Plannotator 使用以下规则自动提取标签：</p><ol><li><strong>默认标签</strong>：总是包含 <code>plannotator</code> 标签</li><li><strong>项目名标签</strong>：从 git 仓库名或目录名自动提取</li><li><strong>标题关键词</strong>：从第一个 H1 标题中提取有意义的词（排除常见停用词）</li><li><strong>代码语言标签</strong>：从代码块的语言标识符提取（例如 <code>typescript</code>、<code>sql</code>）。通用配置语言（如 <code>json</code>、<code>yaml</code>、<code>markdown</code>）会被自动过滤。</li></ol><p>停用词列表（不会作为标签）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>标签数量限制：最多 7 个标签，按提取顺序排列。</p><h3 id="文件名格式" tabindex="-1">文件名格式 <a class="header-anchor" href="#文件名格式" aria-label="Permalink to &quot;文件名格式&quot;">​</a></h3><p>文件名采用可读性强的格式：<code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>部分</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>标题</td><td><code>User Authentication</code></td><td>从 H1 提取，限制 50 字符</td></tr><tr><td>日期</td><td><code>Jan 2, 2026</code></td><td>当前日期</td></tr><tr><td>时间</td><td><code>2-30pm</code></td><td>当前时间（12 小时制）</td></tr></tbody></table><h3 id="backlink-机制" tabindex="-1">Backlink 机制 <a class="header-anchor" href="#backlink-机制" aria-label="Permalink to &quot;Backlink 机制&quot;">​</a></h3><p>每个计划文件底部都会插入 <code>[[Plannotator Plans]]</code> 链接。这个 backlink 的作用：</p><ul><li><strong>知识图谱连接</strong>：在 Obsidian 的 graph view 中，所有计划都与同一个节点连接</li><li><strong>快速导航</strong>：点击 <code>[[Plannotator Plans]]</code> 可以创建一个索引页面，汇总所有保存的计划</li><li><strong>双向链接</strong>：在索引页面中使用反向链接查看所有计划</li></ul><h2 id="跨平台支持" tabindex="-1">跨平台支持 <a class="header-anchor" href="#跨平台支持" aria-label="Permalink to &quot;跨平台支持&quot;">​</a></h2><p>Plannotator 自动检测不同操作系统的 Obsidian 配置文件位置：</p><table tabindex="0"><thead><tr><th>操作系统</th><th>配置文件路径</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>如果自动检测失败，可以手动输入 vault 路径。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="问题-1-检测不到-vaults" tabindex="-1">问题 1：检测不到 vaults <a class="header-anchor" href="#问题-1-检测不到-vaults" aria-label="Permalink to &quot;问题 1：检测不到 vaults&quot;">​</a></h3><p><strong>症状</strong>：下拉菜单显示&quot;Detecting...&quot;但没有结果</p><p><strong>原因</strong>：Obsidian 配置文件不存在或格式错误</p><p><strong>解决方案</strong>：</p><ol><li>确认 Obsidian 已安装并至少打开过一次</li><li>检查配置文件是否存在（参考上表路径）</li><li>使用&quot;Custom path...&quot;手动输入 vault 路径</li></ol><h3 id="问题-2-保存后找不到文件" tabindex="-1">问题 2：保存后找不到文件 <a class="header-anchor" href="#问题-2-保存后找不到文件" aria-label="Permalink to &quot;问题 2：保存后找不到文件&quot;">​</a></h3><p><strong>症状</strong>：批准计划后，Obsidian 中没有新文件</p><p><strong>原因</strong>：vault 路径错误或 Obsidian 未刷新</p><p><strong>解决方案</strong>：</p><ol><li>检查设置面板中的预览路径是否正确</li><li>在 Obsidian 中点击&quot;Reload vault&quot;或按 <code>Cmd+R</code>（macOS）/ <code>Ctrl+R</code>（Windows/Linux）</li><li>检查是否选择了正确的 vault</li></ol><h3 id="问题-3-文件名包含特殊字符" tabindex="-1">问题 3：文件名包含特殊字符 <a class="header-anchor" href="#问题-3-文件名包含特殊字符" aria-label="Permalink to &quot;问题 3：文件名包含特殊字符&quot;">​</a></h3><p><strong>症状</strong>：文件名中出现 <code>_</code> 或其他替换字符</p><p><strong>原因</strong>：标题包含文件系统不支持的字符（<code>&lt; &gt; : &quot; / \\ | ? *</code>）</p><p><strong>解决方案</strong>：这是预期行为，Plannotator 会自动替换这些字符以避免文件系统错误。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Obsidian 集成功能让你的计划评审流程与知识管理无缝连接：</p><ul><li>✅ 自动保存批准或拒绝的计划</li><li>✅ 智能提取标签，方便后续检索</li><li>✅ 生成 frontmatter，统一元数据格式</li><li>✅ 添加 backlink，构建知识图谱</li></ul><p>配置一次后，每次评审都会自动归档，不再需要手动复制粘贴。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../bear-integration/">Bear 集成</a></strong>。</p><p>你会学到：</p><ul><li>如何将计划保存到 Bear 笔记应用</li><li>Bear 集成与 Obsidian 集成的区别</li><li>使用 x-callback-url 自动创建笔记</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>检测 Obsidian vaults</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>保存计划到 Obsidian</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>提取标签</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>生成 frontmatter</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>生成文件名</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Obsidian 设置存储</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Settings UI 组件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>关键函数</strong>：</p><ul><li><code>detectObsidianVaults()</code>：读取 Obsidian 配置文件，返回可用的 vault 路径列表</li><li><code>saveToObsidian(config)</code>：将计划保存到指定 vault，包含 frontmatter 和 backlink</li><li><code>extractTags(markdown)</code>：从计划内容提取标签（标题关键词、代码语言、项目名）</li><li><code>generateFrontmatter(tags)</code>：生成 YAML frontmatter 字符串</li><li><code>generateFilename(markdown)</code>：生成可读的文件名</li></ul><p><strong>业务规则</strong>：</p><ul><li>标签数量最多 7 个（L73）</li><li>文件名限制 50 字符（L102）</li><li>支持跨平台配置文件路径检测（L141-149）</li><li>自动创建不存在的文件夹（L208）</li></ul></details>`,79)])])}const u=a(n,[["render",r]]);export{b as __pageData,u as default};
